import{_ as e,o as a,c as s,a2 as n}from"./chunks/framework.D36jym0Z.js";const g=JSON.parse('{"title":"Host Adapters","description":"","frontmatter":{},"headers":[],"relativePath":"platform-concepts/host-adapters.md","filePath":"platform-concepts/host-adapters.md","lastUpdated":1784629191000}'),o={name:"platform-concepts/host-adapters.md"};function i(l,t,r,p,d,h){return a(),s("div",null,[...t[0]||(t[0]=[n(`<h1 id="host-adapters" tabindex="-1">Host Adapters <a class="header-anchor" href="#host-adapters" aria-label="Permalink to &quot;Host Adapters&quot;">​</a></h1><p>A host adapter is the <strong>integration layer</strong> between an agent host (OpenClaw, Codex, Claude Code) and the LightMem2 core runtime. It translates host-specific events, APIs, and configuration into the standardized format that plugins expect.</p><h2 id="why-adapters-exist" tabindex="-1">Why Adapters Exist <a class="header-anchor" href="#why-adapters-exist" aria-label="Permalink to &quot;Why Adapters Exist&quot;">​</a></h2><p>Agent hosts differ in:</p><ul><li><strong>Event models</strong>: how they signal session start, message received, tool called, session end</li><li><strong>Configuration</strong>: where and how settings are stored (JSON, TOML, env vars)</li><li><strong>Context APIs</strong>: how the prompt/context is assembled and sent to the model</li><li><strong>Hook systems</strong>: how external code can intercept or modify behavior</li></ul><p>The adapter abstracts these differences so plugins only deal with one consistent interface.</p><h2 id="adapter-responsibilities" tabindex="-1">Adapter Responsibilities <a class="header-anchor" href="#adapter-responsibilities" aria-label="Permalink to &quot;Adapter Responsibilities&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                Host Adapter                 │</span></span>
<span class="line"><span>├────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  1. Event translation                      │</span></span>
<span class="line"><span>│     Host-specific events → standard events  │</span></span>
<span class="line"><span>├────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  2. Configuration integration              │</span></span>
<span class="line"><span>│     Reads host config, merges with plugin   │</span></span>
<span class="line"><span>│     config, writes back when needed         │</span></span>
<span class="line"><span>├────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  3. Context interception                    │</span></span>
<span class="line"><span>│     Hooks into the host&#39;s context pipeline  │</span></span>
<span class="line"><span>│     so plugins can read/modify context      │</span></span>
<span class="line"><span>├────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  4. Proxy / Gateway                         │</span></span>
<span class="line"><span>│     When the host doesn&#39;t support native    │</span></span>
<span class="line"><span>│     hooks, the adapter runs a local proxy   │</span></span>
<span class="line"><span>├────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  5. CLI surface                             │</span></span>
<span class="line"><span>│     Exposes host-specific commands through  │</span></span>
<span class="line"><span>│     the shared lightmem2 CLI                │</span></span>
<span class="line"><span>└────────────────────────────────────────────┘</span></span></code></pre></div><h2 id="current-adapters" tabindex="-1">Current Adapters <a class="header-anchor" href="#current-adapters" aria-label="Permalink to &quot;Current Adapters&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Host</th><th style="text-align:left;">Adapter Location</th><th style="text-align:left;">Integration Style</th></tr></thead><tbody><tr><td style="text-align:left;">OpenClaw</td><td style="text-align:left;"><code>components/adapters/openclaw/</code></td><td style="text-align:left;">Native plugin slot + restart</td></tr><tr><td style="text-align:left;">Codex</td><td style="text-align:left;"><code>components/adapters/codex/</code></td><td style="text-align:left;">Local proxy + hooks</td></tr><tr><td style="text-align:left;">Claude Code</td><td style="text-align:left;"><code>components/adapters/claude-code/</code></td><td style="text-align:left;">Local gateway + MCP</td></tr></tbody></table><h2 id="integration-patterns" tabindex="-1">Integration Patterns <a class="header-anchor" href="#integration-patterns" aria-label="Permalink to &quot;Integration Patterns&quot;">​</a></h2><h3 id="native-plugin-slot-openclaw" tabindex="-1">Native Plugin Slot (OpenClaw) <a class="header-anchor" href="#native-plugin-slot-openclaw" aria-label="Permalink to &quot;Native Plugin Slot (OpenClaw)&quot;">​</a></h3><p>The host itself provides a plugin mechanism. The adapter registers as a plugin and receives events directly.</p><h3 id="proxy-gateway-codex-claude-code" tabindex="-1">Proxy/Gateway (Codex, Claude Code) <a class="header-anchor" href="#proxy-gateway-codex-claude-code" aria-label="Permalink to &quot;Proxy/Gateway (Codex, Claude Code)&quot;">​</a></h3><p>When the host doesn&#39;t have native plugin support, the adapter runs as a <strong>local proxy</strong> that sits between the host and the model API. It intercepts requests, applies plugin transformations, and forwards the modified context.</p><p>The proxy pattern enables:</p><ul><li>Full context visibility without host modifications</li><li>Consistent behavior across hosts with different internals</li><li>Graceful degradation if the proxy is stopped</li></ul><h2 id="adapter-lifecycle" tabindex="-1">Adapter Lifecycle <a class="header-anchor" href="#adapter-lifecycle" aria-label="Permalink to &quot;Adapter Lifecycle&quot;">​</a></h2><ol><li><strong>Install</strong>: Write config files, register hooks, set up proxy autostart</li><li><strong>Start</strong>: Proxy/gateway starts, hooks activate</li><li><strong>Run</strong>: Events flow through adapter → core → plugins → adapter → host</li><li><strong>Stop</strong>: Gateway shuts down, hooks deactivate</li><li><strong>Uninstall</strong>: Config files restored from <code>.tokenpilot.bak</code> backups</li></ol><h2 id="next" tabindex="-1">Next <a class="header-anchor" href="#next" aria-label="Permalink to &quot;Next&quot;">​</a></h2><ul><li><a href="/LightMem2/hosts/compatibility">Host Compatibility</a> — which features work on which host</li><li><a href="/LightMem2/host-adapter-development/adding-new-host">Adding a New Host</a> — build your own adapter</li><li><a href="/LightMem2/host-adapter-development/adapter-architecture">Adapter Architecture</a> — deep dive</li></ul>`,21)])])}const u=e(o,[["render",i]]);export{g as __pageData,u as default};
